    // HTML congelado para release (sem File.Contents)
    P1 = "<!DOCTYPE html>#(lf)<html lang=""pt-BR"">#(lf)<head>#(lf)<meta charset=""UTF-8"" />#(lf)<meta name=""viewport"" content=""width=device-width,initial-scale=1"" />#(lf)<title>Dashboard Desospitalizacao</title>#(lf)<style>#(lf)/* Tema visual alinhado ao thema.json (tons de verde + azul institucional). */#(lf):root {#(lf)  --brand-green: #4c7230;#(lf)  --brand-blue: #094780;#(lf)  --brand-green-2: #298148;#(lf)  --bg: #f5f7f3;#(lf)  --surface: #ffffff;#(lf)  --text: #1c2614;#(lf)  --muted: #6d7665;#(lf)  --border: #dbe3d6;#(lf)  --ok: #2f8f46;#(lf)  --warn: #b58a22;#(lf)  --bad: #b93a32;#(lf)}#(lf)/* Reset basico e layout global da pagina HTML Content. */#(lf)* { box-sizing: border-box; }#(lf)html, body {#(lf)  margin: 0;#(lf)  padding: 0;#(lf)  font-family: ""Segoe UI"", ""Calibri"", sans-serif;#(lf)  color: var(--text);#(lf)  background: linear-gradient(180deg, #f7faf5 0%, #edf3e8 100%);#(lf)}#(lf)/* Container principal da sessao unica ""dashboard"". */#(lf).dashboard {#(lf)  width: 100%;#(lf)  min-height: 100vh;#(lf)  padding: 14px;#(lf)}#(lf).topbar {#(lf)  display: flex;#(lf)  flex-wrap: wrap;#(lf)  justify-content: space-between;#(lf)  gap: 10px;#(lf)  align-items: center;#(lf)  margin-bottom: 10px;#(lf)}#(lf).title-wrap h1 {#(lf)  margin: 0;#(lf)  font-size: 20px;#(lf)  color: var(--brand-green);#(lf)}#(lf).title-wrap p {#(lf)  margin: 2px 0 0;#(lf)  font-size: 12px;#(lf)  color: var(--muted);#(lf)}#(lf).meta {#(lf)  font-size: 11px;#(lf)  color: var(--muted);#(lf)}#(lf)/* Bloco de filtros internos (sem slicer nativo do Power BI). */#(lf).filters {#(lf)  background: var(--surface);#(lf)  border: 1px solid var(--border);#(lf)  border-radius: 10px;#(lf)  padding: 10px;#(lf)  display: grid;#(lf)  grid-template-columns: repeat(auto-fit, minmax(160px, 1fr));#(lf)  gap: 8px;#(lf)  margin-bottom: 10px;#(lf)}#(lf).filter {#(lf)  display: flex;#(lf)  flex-direction: column;#(lf)  gap: 4px;#(lf)}#(lf).filter label {#(lf)  font-size: 11px;#(lf)  color: var(--muted);#(lf)  text-transform: uppercase;#(lf)  letter-spacing: .3px;#(lf)}#(lf).filter input,#(lf).filter select,#(lf).filter button {#(lf)  height: 32px;#(lf)  border: 1px solid var(--border);#(lf)  border-radius: 8px;#(lf)  background: #fff;#(lf)  color: var(--text);#(lf)  padding: 0 9px;#(lf)  font-size: 12px;#(lf)}#(lf).filter button {#(lf)  background: var(--brand-green);#(lf)  color: #fff;#(lf)  border: none;#(lf)  font-weight: 600;#(lf)  cursor: pointer;#(lf)}#(lf).filter button:hover { background: #355022; }#(lf)/* Grade compacta de cards executivos/operacionais. */#(lf).cards {#(lf)  display: grid;#(lf)  grid-template-columns: repeat(auto-fit, minmax(170px, 1fr));#(lf)  gap: 8px;#(lf)  margin-bottom: 10px;#(lf)}#(lf).card {#(lf)  background: var(--surface);#(lf)  border: 1px solid var(--border);#(lf)  border-top: 4px solid var(--brand-green);#(lf)  border-radius: 10px;#(lf)  padding: 9px;#(lf)  min-height: 82px;#(lf)}#(lf).card.ok { border-top-color: var(--ok); }#(lf).card.warn { border-top-color: var(--warn); }#(lf).card.bad { border-top-color: var(--bad); }#(lf).card .k {#(lf)  font-size: 10px;#(lf)  color: var(--muted);#(lf)  text-transform: uppercase;#(lf)  letter-spacing: .4px;#(lf)}#(lf).card .v {#(lf)  margin-top: 6px;#(lf)  font-size: 26px;#(lf)  font-weight: 700;#(lf)  line-height: 1;#(lf)}#(lf).card .s {#(lf)  margin-top: 4px;#(lf)  font-size: 11px;#(lf)  color: var(--muted);#(lf)}#(lf)/* Tabela detalhada de permanencia com cabecalho fixo. */#(lf).table-wrap {#(lf)  background: var(--surface);#(lf)  border: 1px solid var(--border);#(lf)  border-radius: 10px;#(lf)  overflow: hidden;#(lf)}#(lf).table-head {#(lf)  padding: 10px;#(lf)  border-bottom: 1px solid var(--border);#(lf)  display: flex;#(lf)  justify-content: space-between;#(lf)  align-items: center;#(lf)  gap: 8px;#(lf)}#(lf).table-head h2 {#(lf)  margin: 0;#(lf)  font-size: 14px;#(lf)  color: var(--brand-blue);#(lf)}#(lf).table-head span {#(lf)  font-size: 11px;#(lf)  color: var(--muted);#(lf)}#(lf).table-scroll {#(lf)  max-height: calc(100vh - 320px);#(lf)  overflow: auto;#(lf)}#(lf).table {#(lf)  width: 100%;#(lf)  border-collapse: collapse;#(lf)  font-size: 11px;#(lf)}#(lf).table thead th {#(lf)  position: sticky;#(lf)  top: 0;#(lf)  background: #f3f6ef;#(lf)  color: #3f4b34;#(lf)  text-align: left;#(lf)  padding: 7px 8px;#(lf)  border-bottom: 1px solid var(--border);#(lf)  white-space: nowrap;#(lf)}#(lf).table tbody td {#(lf)  padding: 6px 8px;#(lf)  border-bottom: 1px solid #eef3ea;#(lf)  vertical-align: middle;#(lf)}#(lf).table tbody tr:hover td { background: #f8fbf6; }#(lf).badge {#(lf)  display: inline-block;#(lf)  padding: 2px 8px;#(lf)  border-radius: 999px;#(lf)  font-size: 10px;#(lf)  font-weight: 700;#(lf)}#(lf).badge.ok { background: #e8f6ea; color: #1f7a34; }#(lf).badge.bad { background: #fdeceb; color: #a82b24; }#(lf)/* Responsividade basica para telas menores. */#(lf)@media (max-width: 900px) {#(lf)  .table-scroll { max-height: none; }#(lf)}#(lf)</style>#(lf)</head>#(lf)<body>#(lf)<!-- Sessao unica: titulo + filtros + cards + tabela detalhada. -->#(lf)<div class=""dashboard"">#(lf)  <div class=""topbar"">#(lf)    <div class=""title-wrap"">#(lf)      <h1>Dashboard Desospitalizacao</h1>#(lf)      <p>Indicadores Operacionais</p>#(lf)    </div>#(lf)    <div class=""meta"" id=""meta-resumo"">Aguardando dados...</div>#(lf)  </div>#(lf)#(lf)  <div class=""filters"">#(lf)    <div class=""filter"">#(lf)      <label>Data inicial</label>#(lf)      <input type=""date"" id=""f-data-inicial"" />#(lf)    </div>#(lf)    <div class=""filter"">#(lf)      <label>Data final</label>#(lf)      <input type=""date"" id=""f-data-final"" />#(lf)    </div>#(lf)    <div class=""filter"">#(lf)      <label>Estabelecimento</label>#(lf)      <select id=""f-estabelecimento""></select>#(lf)    </div>#(lf)    <div class=""filter"">#(lf)      <label>Setor</label>#(lf)      <select id=""f-setor""></select>#(lf)    </div>#(lf)    <div class=""filter"">#(lf)      <label>Medico</label>#(lf)      <select id=""f-medico""></select>#(lf)    </div>#(lf)    <div class=""filter"">#(lf)      <label>Acao</label>#(lf)      <button id=""btn-limpar"">Limpar filtros</button>#(lf)    </div>#(lf)  </div>#(lf)#(lf)  <div class=""cards"" id=""cards""></div>#(lf)#(lf)  <div class=""table-wrap"">#(lf)    <div class=""table-head"">#(lf)      <h2>Tabela detalhada de permanencia</h2>#(lf)      <span id=""table-count"">0 linhas</span>#(lf)    </div>#(lf)    <div class=""table-scroll"">#(lf)      <table class=""table"" id=""tbl-detalhe"">#(lf)        <thead>#(lf)          <tr>#(lf)            <th>Atendimento</th>#(lf)            <th>Paciente</th>#(lf)            <th>Entrada</th>#(lf)         ",
    P2 = "   <th>Estab.</th>#(lf)            <th>Setor</th>#(lf)            <th>Medico</th>#(lf)            <th>CID</th>#(lf)            <th>Dias</th>#(lf)            <th>Media Setor/CID</th>#(lf)            <th>Desvio</th>#(lf)            <th>Status</th>#(lf)          </tr>#(lf)        </thead>#(lf)        <tbody id=""tbl-detalhe-body""></tbody>#(lf)      </table>#(lf)    </div>#(lf)  </div>#(lf)</div>#(lf)#(lf)<script>#(lf)// Estado central: todos os arrays serializados em DAX na measure JSON Dashboard Compacto.#(lf)var dashboardData = { tat: [], perm: [], acur: [], readm: [], uti: [], meta: {} };#(lf)#(lf)// Converte valor em numero com fallback 0 (evita NaN no render).#(lf)function n(v) {#(lf)  var x = Number(v);#(lf)  return isNaN(x) ? 0 : x;#(lf)}#(lf)#(lf)// Calcula mediana para os cards de permanencia/erro.#(lf)function median(values) {#(lf)  if (!values || !values.length) return 0;#(lf)  var arr = values.slice().sort(function(a, b) { return a - b; });#(lf)  var m = Math.floor(arr.length / 2);#(lf)  return arr.length % 2 ? arr[m] : (arr[m - 1] + arr[m]) / 2;#(lf)}#(lf)#(lf)// Formata numero em padrao pt-BR simples (virgula decimal).#(lf)function fmt(v, d) {#(lf)  return n(v).toFixed(d || 0).replace('.', ',');#(lf)}#(lf)#(lf)// Popula selects de filtro com opcao ""Todos"".#(lf)function fillSelect(id, values, label) {#(lf)  var el = document.getElementById(id);#(lf)  if (!el) return;#(lf)  var html = '<option value=""__ALL__"">' + label + '</option>';#(lf)  for (var i = 0; i < values.length; i++) {#(lf)    html += '<option value=""' + values[i] + '"">' + values[i] + '</option>';#(lf)  }#(lf)  el.innerHTML = html;#(lf)}#(lf)#(lf)// Regras de passagem de filtro por linha (data + dimensoes).#(lf)function rowPass(row, f) {#(lf)  var d = (row && row.d) ? String(row.d) : '';#(lf)  if (f.di && d && d < f.di) return false;#(lf)  if (f.df && d && d > f.df) return false;#(lf)#(lf)  var e = row && row.e ? String(row.e) : '*';#(lf)  var s = row && row.s ? String(row.s) : '*';#(lf)  var m = row && row.m ? String(row.m) : '*';#(lf)#(lf)  if (f.e !== '__ALL__' && e !== '*' && e !== f.e) return false;#(lf)  if (f.s !== '__ALL__' && s !== '*' && s !== f.s) return false;#(lf)  if (f.m !== '__ALL__' && m !== '*' && m !== f.m) return false;#(lf)  return true;#(lf)}#(lf)#(lf)// Le os filtros atuais do DOM.#(lf)function getFilters() {#(lf)  return {#(lf)    di: document.getElementById('f-data-inicial').value || '',#(lf)    df: document.getElementById('f-data-final').value || '',#(lf)    e: document.getElementById('f-estabelecimento').value || '__ALL__',#(lf)    s: document.getElementById('f-setor').value || '__ALL__',#(lf)    m: document.getElementById('f-medico').value || '__ALL__'#(lf)  };#(lf)}#(lf)#(lf)// Semaforo simples dos cards (cores por faixa).#(lf)function status(metric, value) {#(lf)  if (metric === 'readm7') return value <= 5 ? 'ok' : (value <= 8 ? 'warn' : 'bad');#(lf)  if (metric === 'readm30') return value <= 12 ? 'ok' : (value <= 16 ? 'warn' : 'bad');#(lf)  if (metric === 'acur') return value >= 80 ? 'ok' : (value >= 70 ? 'warn' : 'bad');#(lf)  if (metric === 'perm') return value <= 10 ? 'ok' : (value <= 14 ? 'warn' : 'bad');#(lf)  if (metric === 'sla') return value <= 20 ? 'ok' : (value <= 30 ? 'warn' : 'bad');#(lf)  return '';#(lf)}#(lf)#(lf)// Renderiza todos os cards compactos.#(lf)function renderCards(cards) {#(lf)  var host = document.getElementById('cards');#(lf)  if (!host) return;#(lf)  var html = '';#(lf)  for (var i = 0; i < cards.length; i++) {#(lf)    var c = cards[i];#(lf)    html += '<div class=""card ' + (c.status || '') + '"">';#(lf)    html += '<div class=""k"">' + c.k + '</div>';#(lf)    html += '<div class=""v"">' + c.v + '</div>';#(lf)    html += '<div class=""s"">' + c.s + '</div>';#(lf)    html += '</div>';#(lf)  }#(lf)  host.innerHTML = html;#(lf)}#(lf)#(lf)// Renderiza tabela detalhada de permanencia (ordenada por desvio).#(lf)function renderTable(rows) {#(lf)  var body = document.getElementById('tbl-detalhe-body');#(lf)  var cnt = document.getElementById('table-count');#(lf)  if (!body) return;#(lf)  if (!rows.length) {#(lf)    body.innerHTML = '<tr><td colspan=""11"" style=""text-align:center;color:#6d7665"">Sem dados para os filtros selecionados.</td></tr>';#(lf)    if (cnt) cnt.textContent = '0 linhas';#(lf)    return;#(lf)  }#(lf)#(lf)  rows.sort(function(a, b) { return n(b.desvio) - n(a.desvio); });#(lf)  var top = rows.slice(0, 120);#(lf)  var html = '';#(lf)  for (var i = 0; i < top.length; i++) {#(lf)    var r = top[i];#(lf)    var fc = n(r.fora) > 0;#(lf)    html += '<tr>' +#(lf)      '<td>' + (r.att || '-') + '</td>' +#(lf)      '<td>' + (r.pac || '-') + '</td>' +#(lf)      '<td>' + (r.d || '-') + '</td>' +#(lf)      '<td>' + (r.e || '-') + '</td>' +#(lf)      '<td>' + (r.s || '-') + '</td>' +#(lf)      '<td>' + (r.m || '-') + '</td>' +#(lf)      '<td>' + (r.cid || '-') + '</td>' +#(lf)      '<td>' + fmt(r.dias, 1) + '</td>' +#(lf)      '<td>' + fmt(r.media, 1) + '</td>' +#(lf)      '<td>' + fmt(r.desvio, 1) + '</td>' +#(lf)      '<td><span class=""badge ' + (fc ? 'bad' : 'ok') + '"">' + (fc ? 'Fora curva' : 'OK') + '</span></td>' +#(lf)      '</tr>';#(lf)  }#(lf)  body.innerHTML = html;#(lf)  if (cnt) cnt.textContent = top.length + ' de ' + rows.length + ' linhas';#(lf)}#(lf)#(lf)// Recalcula tudo ao mudar qualquer filtro.#(lf)// Mapeamento de KPIs:#(lf)// - tat: Soma TAT, Media TAT, % SLA#(lf)// - perm: Media/Mediana, Fora da Curva, Desvio#(lf)// - acur: Acuracia e erros de previsao#(lf)// - readm: taxas 7d e 30d#(lf)// - uti: retorno UTI 48h#(lf)function refresh() {#(lf)  var f = getFilters();#(lf)#(lf)  var tat = dashboardData.tat.filter(function(r) { return rowPass(r, f); });#(lf)  var perm = dashboardData.perm.filter(function(r) { return rowPass(r, f); });#(lf)  var acur = dashboardData.acur.filter(function(r) { return rowPass(r, f); });#(lf)  var readm = dashboardData.readm.filter(function(r) { return rowPass(r, f); });#(lf)  var uti = dashboardData.uti.filter(function(r) { return rowPass(r, f); });#(lf)#(lf)  var tatCnt = 0, tatSoma = 0, tatSla = 0;#(lf)  for (var i = 0; i < tat.length; i++) {#(lf)    tatCnt += n(tat[i].cnt || 1);#(lf)    tatSoma += n(tat[i].tat);#(lf)    tatSla += n(tat[i].sla);#(lf)  }#(lf)  var tatMedia = tatCnt ?",
    P3 = " tatSoma / tatCnt : 0;#(lf)  var slaPct = tatCnt ? (tatSla / tatCnt) * 100 : 0;#(lf)#(lf)  var dias = [], diasSoma = 0, foraCurva = 0, desvioSoma = 0;#(lf)  for (var j = 0; j < perm.length; j++) {#(lf)    var d = n(perm[j].dias);#(lf)    dias.push(d);#(lf)    diasSoma += d;#(lf)    foraCurva += n(perm[j].fora);#(lf)    desvioSoma += n(perm[j].desvio);#(lf)  }#(lf)  var permMedia = perm.length ? diasSoma / perm.length : 0;#(lf)  var permMediana = median(dias);#(lf)  var desvioMedio = perm.length ? desvioSoma / perm.length : 0;#(lf)#(lf)  var acurPct = 0, erroList = [], erroSoma = 0;#(lf)  for (var k = 0; k < acur.length; k++) {#(lf)    acurPct += n(acur[k].acur);#(lf)    var dif = Math.abs(n(acur[k].dif));#(lf)    erroList.push(dif);#(lf)    erroSoma += dif;#(lf)  }#(lf)  acurPct = acur.length ? acurPct / acur.length : 0;#(lf)  var erroMedio = acur.length ? erroSoma / acur.length : 0;#(lf)  var erroMediano = median(erroList);#(lf)#(lf)  var den7 = 0, num7 = 0, den30 = 0, num30 = 0;#(lf)  for (var m = 0; m < readm.length; m++) {#(lf)    den7 += n(readm[m].den7);#(lf)    num7 += n(readm[m].num7);#(lf)    den30 += n(readm[m].den30);#(lf)    num30 += n(readm[m].num30);#(lf)  }#(lf)  var tx7 = den7 ? (num7 / den7) * 100 : 0;#(lf)  var tx30 = den30 ? (num30 / den30) * 100 : 0;#(lf)#(lf)  var ret48 = 0;#(lf)  for (var u = 0; u < uti.length; u++) ret48 += n(uti[u].ret48);#(lf)#(lf)  var cards = [#(lf)    { k: 'Soma TAT (h)', v: fmt(tatSoma, 1), s: tatCnt + ' exames', status: '' },#(lf)    { k: 'Media TAT (h)', v: fmt(tatMedia, 1), s: 'Prompt1 Executivo', status: '' },#(lf)    { k: '% Exames Acima SLA', v: fmt(slaPct, 1) + '%', s: 'SLA 24h', status: status('sla', slaPct) },#(lf)    { k: 'Media Permanencia (dias)', v: fmt(permMedia, 1), s: perm.length + ' atend.', status: status('perm', permMedia) },#(lf)    { k: 'Mediana Permanencia (dias)', v: fmt(permMediana, 1), s: 'Prompt1 Executivo', status: '' },#(lf)    { k: 'Pacientes Fora da Curva', v: fmt(foraCurva, 0), s: