 var minD = '', maxD = '';#(lf)#(lf)  for (var i = 0; i < rows.length; i++) {#(lf)    var r = rows[i] || {};#(lf)    if (r.e && r.e !== '*') estSet[String(r.e)] = true;#(lf)    if (r.s && r.s !== '*') setorSet[String(r.s)] = true;#(lf)    if (r.m && r.m !== '*') medSet[String(r.m)] = true;#(lf)    if (r.d) {#(lf)      if (!minD || r.d < minD) minD = r.d;#(lf)      if (!maxD || r.d > maxD) maxD = r.d;#(lf)    }#(lf)  }#(lf)#(lf)  var est = Object.keys(estSet).sort();#(lf)  var setor = Object.keys(setorSet).sort();#(lf)  var med = Object.keys(medSet).sort();#(lf)#(lf)  fillSelect('f-estabelecimento', est, 'Todos');#(lf)  fillSelect('f-setor', setor, 'Todos');#(lf)  fillSelect('f-medico', med, 'Todos');#(lf)#(lf)  var di = document.getElementById('f-data-inicial');#(lf)  var df = document.getElementById('f-data-final');#(lf)  if (di && minD) di.value = minD;#(lf)  if (df && maxD) df.value = maxD;#(lf)#(lf)  ['f-data-inicial', 'f-data-final', 'f-estabelecimento', 'f-setor', 'f-medico'].forEach(function(id) {#(lf)    var el = document.getElementById(id);#(lf)    if (el) el.addEventListener('change', refresh);#(lf)  });#(lf)#(lf)  var clear = document.getElementById('btn-limpar');#(lf)  if (clear) {#(lf)    clear.addEventListener('click', function() {#(lf)      if (di) di.value = minD || '';#(lf)      if (df) df.value = maxD || '';#(lf)      document.getElementById('f-estabelecimento').value = '__ALL__';#(lf)      document.getElementById('f-setor').value = '__ALL__';#(lf)      document.getElementById('f-medico').value = '__ALL__';#(lf)      refresh();#(lf)    });#(lf)  }#(lf)}#(lf)#(lf)// Ponto de entrada chamado pela measure [HTML Dashboard].#(lf)// Recebe objeto JSON completo e dispara bootstrap da tela.#(lf)function initDashboard(cfg) {#(lf)  dashboardData = cfg || {};#(lf)  dashboardData.tat = dashboardData.tat || [];#(lf)  dashboardData.perm = dashboardData.perm || [];#(lf)  dashboardData.acur = dashboardData.acur || [];#(lf)  dashboardData.readm = dashboardData.read